var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS001L0932-55: <color=#ffd34c>【기록-439】 검토 회의</color>","JPN":"AEGIS 8 PBLIT SECURITY SEQUENCE：<color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR：<color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS001L0932-55：<color=#ffd34c>【記録-439】 検討会議</color>","ENG":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS001L0932-55: <color=#ffd34c>【Record-439】 Review Conference</color>","TWN":"AEGIS 8 PBLIT SECURITY SEQUENCE: <color=#ffd34c>ACTIVATED</color>     \\nADC FACTOR: <color=#ffd34c>ALPHA CONFIRMED</color>     \\nCCN No. FS001L0932-55: <color=#ffd34c>【記錄-439】 討論會議</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......사내 평가 청취는 이상으로 마치겠습니다.","JPN":"……社内評価の聴取は以上です。","ENG":"That's the end of her evaluation within the company.","TWN":"……公司內部評價到此結束。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"방금 그 아가씨, 누군지 몰라도 말이 거침없군.","JPN":"さっきの女性、誰だか知らないがよどみないな。","ENG":"I don't know who that woman is, but she's ruthless.","TWN":"剛才那位小姐，雖然不知道是誰，但真是健談呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그야 회사 최고참 직원 중의 한 명인 관리부 <color=#ff3636>[CENSORED]</color> 부장이니까요.","JPN":"それは、勤務期間が一番長いメンバーの一人、管理部の<color=#ff3636>[CENSORED]</color>部長ですから。","ENG":"She's Manager <color=#ff3636>[CENSORED]</color>, one of the senior employees at the Managerial Department.","TWN":"那是因為他是我們公司的最老的員工之一，管理部的<color=#ff3636>[CENSORED]</color>部長。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그 정도 연차가 되면 조신함 따위를 기대하는 건 무리가 있죠.","JPN":"それだけの古参に、控え目のコメントなんて無理でしょう。","ENG":"It's hard to expect a lot of modesty at her level of seniority.","TWN":"都已經是這個年資了，你不用期待他能管得住自己的嘴巴。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"평가가 가차없군.......","JPN":"評価が容赦ないな……","ENG":"You're ruthless as well...","TWN":"你的評價也太無情了吧……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"하긴 틀린 말도 아니지.","JPN":"だが、間違ってるとも言えない。","ENG":"But what she said is true.","TWN":"雖然也沒說錯什麼。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"<color=#ff3636>[DATA EXPUNGED]</color> 시절에도 힐데 전대장이라면 믿고 따르는 사람이 많았으니까.","JPN":"<color=#ff3636>[DATA EXPUNGED]</color>時代にも、ヒルデ戦隊長なら信頼して従う人が多かった。","ENG":"There were a lot of people who believed in Commander Hilde back during the <color=#ff3636>[DATA EXPUNGED]</color>.","TWN":"畢竟在<color=#ff3636>[DATA_EXPUNGED]</color>時代，相信並追隨希爾德指揮官的人也很多。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"성격이야 어쨌든, 항상 성과로 증명하는 사람이니까 말일세.","JPN":"性格はともかく、いつも成果で証明するからな。","ENG":"Regardless of her personality, she always proves herself with results.","TWN":"撇開個性不談，她是個用成果來證明一切的人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"말 그대로 전설 속의 발키리 아니겠나.","JPN":"言葉通り、伝説のヴァルキリーだ。","ENG":"She's literally a Valkyrie from the legends.","TWN":"就跟字面上說的一樣，是傳說中的女武神呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"남 이야기 할 필요가 없지, 자네도 그때는.......","JPN":"他の人の話をするまでもない。あの時は君も……","ENG":"Speaking of legends, you were also—","TWN":"不用說其他人，你當時也……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"쓸데없는 소리는 넘어가도록 하겠습니다.","JPN":"無駄な話はお控えください。","ENG":"That's completely unrelated to our current subject.","TWN":"請容我跳過這段無謂的討論。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"다음으로는 교우 관계입니다.","JPN":"次は交友関係です。","ENG":"Next up, associates.","TWN":"接下來是人際關係。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......예나 지금이나 이건 별게 없군.","JPN":"……これは、今も昔も変わらないな。","ENG":"She hasn't changed a bit.","TWN":"……不管是過去還是現在，還真是都沒變。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"사적인 관계라고 할 만한 건...... 주시윤 군뿐인가?","JPN":"プライベートな関係は……、アキヤマ・シリュウだけか？","ENG":"Her only personal relationship is... with Joo Shiyoon?","TWN":"可以說有私人關係的……就只有周時雲嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그 둘의 관계를 <color=#ffd34c>사적</color>이라고 정의할 수 있을지는 모르겠지만.......","JPN":"二人の関係を<color=#ffd34c>プライベート</color>だと定義していいのかは、よくわかりませんが……","ENG":"I'm not sure if we can consider their relationship as <color=#ffd34c>personal</color>...","TWN":"雖然不知道能不能把這兩個人的關係定義為<color=#ffd34c>私人</color>……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"일단은 그렇습니다.","JPN":"とりあえずそうです｡","ENG":"But as of now, yes.","TWN":"姑且就當做是這樣吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"제자를 들인 건 <color=#ff3636>[DATA EXPUNGED]</color> 이후에 꽤 오랜만인 것 같은데 무슨 계기라도 있었나?","JPN":"弟子を迎えたのは<color=#ff3636>[DATA EXPUNGED]</color>の後、かなり久々だが何かきっかけがあったのか？","ENG":"It's been a while since she accepted a apprentice since <color=#ff3636>[DATA EXPUNGED]</color>. Was there some sort of a turning point?","TWN":"<color=#ff3636>[DATA_EXPUNGED]</color>以後，就很久沒看到她收徒了，是有什麼契機嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"정확한 내막은 모릅니다만.......","JPN":"詳しい事情はわかりませんが……","ENG":"I don't know about the details...","TWN":"我不知道確切的內幕，不過……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"주시윤 군의 양친과 스승님 사이에 친분이 있었다고 알고 있습니다.","JPN":"アキヤマ・シリュウの両親と師匠が親しかったようです。","ENG":"But Joo Shiyoon's parents were apparently acquainted with Master.","TWN":"倒是知道周時雲的父母和師父之間有交情。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"양친의 사망 직후에 홀로 남은 주시윤 군을 스승님이 맡게 되었고.......","JPN":"両親の死後、一人になったアキヤマ・シリュウを師匠が引き取り……","ENG":"After his parents passed away, Master took Joo Shiyoon under her wings.","TWN":"雙親去世後，師父收留了孤身一人的周時雲君……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"사정상 견습 사원이라는 형태로 코핀 컴퍼니에서 주시윤 군을 고용하게 되었습니다.","JPN":"都合上、研修社員という形でコフィンカンパニーが、アキヤマ・シリュウを採用するに至りました。","ENG":"And she gave him a position in the Coffin Company as a trainee.","TWN":"在規劃上，科芬公司是以見習員工的形式雇用周時雲君的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그 이후는 보고서에 나와 있는 대로입니다.","JPN":"その後は、報告書に記載されている通りです。","ENG":"What happened afterwards is all in the report.","TWN":"之後的事情就跟報告裡寫的一樣。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그렇군.","JPN":"そうか。","ENG":"I see.","TWN":"對了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그런데 주시윤 군 양친의 사망 원인은 뭐지?","JPN":"ところで、アキヤマ・シリュウの両親はなぜ亡くなったんだ？","ENG":"But how did Joo Shiyoon's parents die?","TWN":"話說回來，周時雲父母的死亡原因是什麼？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"관련 자료가 빠진 것 같은데...... 사고 같은 건가?","JPN":"関連資料が抜けているようだが……、事故か？","ENG":"I don't see any information regarding the cause of their deaths. Was it an accident?","TWN":"好像缺了這部分的相關資料……難道是事故嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......모릅니다.","JPN":"……わかりません。","ENG":"I don't know.","TWN":"……我不知道。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"거기에 대해서는 스승님도 별 말씀을 하신 적이 없으니까요.","JPN":"それに関しては、師匠も口をつぐんでいます。","ENG":"Master didn't say much about it.","TWN":"關於那件事，師父也沒說過什麼。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"하지만...... 반대로 생각해 보면 스승님이 함구하신다는 사실 자체가.......","JPN":"しかし……逆に、師匠が口を閉ざしているということ自体が……","ENG":"But, if we look at it the other way around, the fact that she hasn't spoken about it means...","TWN":"但是……反過來想的話，師父會閉口不提的事情本身……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"......<color=#ff3636>[DATA EXPUNGED]</color> 인자 관련자로군.","JPN":"……<color=#ff3636>[DATA EXPUNGED]</color>ファクターに関連してるのか。","ENG":"It's related to the <color=#ff3636>[DATA EXPUNGED]</color> factor.","TWN":"……是<color=#ff3636>[DATA_EXPUNGED]</color>因子的關係者吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"......확률은 높겠죠.","JPN":"……その可能性が高いかと。","ENG":"Very likely.","TWN":"……機率很高。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"그럼 이 두 사람의 미묘한 신경전도 설명이 되는군.","JPN":"なら、この二人の微妙な張り合いも理解できる。","ENG":"That explains the subtle tension between them.","TWN":"那麼，這兩個人之間微妙的氣氛也就說得通了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SOUNDALPHA_VOICE_NULL_NULL","text":{"KOREA":"로맨티스트로군...... 그렇게 생각하지 않나?","JPN":"ロマンチストだな……そう思わないか？","ENG":"She's a romanticist. Don't you think so?","TWN":"真浪漫……你不這樣覺得嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"전혀요.","JPN":"思いません。","ENG":"Definitely not.","TWN":"完全不覺得。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOUNDBETA_VOICE_NULL_NULL","text":{"KOREA":"그냥 우유부단할 뿐입니다.","JPN":"ただ優柔不断なだけです。","ENG":"She's just indecisive.","TWN":"只是優柔寡斷而已。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};